CREATE TRIGGER [dbo].[BillOfProcessProcessWorkElementAttribute_History]ON [dbo].[BillOfProcessProcessWorkElementAttribute]AFTER INSERT, UPDATE, DELETE ASDECLARE @HistoryAction CHAR(1)set @HistoryAction = (SELECT TOP 1 	CASE 		WHEN i.BillOfProcessProcessWorkElementAttributeId IS NOT NULL AND d.BillOfProcessProcessWorkElementAttributeId IS NULL THEN 'I' 		WHEN i.BillOfProcessProcessWorkElementAttributeId IS NOT NULL AND d.BillOfProcessProcessWorkElementAttributeId IS NOT NULL THEN 'U' 		WHEN i.BillOfProcessProcessWorkElementAttributeId IS NULL AND d.BillOfProcessProcessWorkElementAttributeId IS NOT NULL THEN 'D'		ELSE 'NA'	END AS HistoryActionfrom inserted as i	full outer join deleted as d on i.BillOfProcessProcessWorkElementAttributeId = d.BillOfProcessProcessWorkElementAttributeId)IF @HistoryAction = 'I' OR @HistoryAction = 'U'BEGIN	INSERT INTO History.dbo_BillOfProcessProcessWorkElementAttribute([BillOfProcessProcessWorkElementAttributeId], [BillOfProcessProcessWorkElementId], [WorkElementTypeAttributeId], [AttributeValue], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [BillOfProcessProcessWorkElementAttributeId], [BillOfProcessProcessWorkElementId], [WorkElementTypeAttributeId], [AttributeValue], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction 	FROM insertedENDELSE IF @HistoryAction = 'D'BEGIN	INSERT INTO History.dbo_BillOfProcessProcessWorkElementAttribute([BillOfProcessProcessWorkElementAttributeId], [BillOfProcessProcessWorkElementId], [WorkElementTypeAttributeId], [AttributeValue], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],[HistoryAction])	SELECT [BillOfProcessProcessWorkElementAttributeId], [BillOfProcessProcessWorkElementId], [WorkElementTypeAttributeId], [AttributeValue], [LastModifiedBy], [LastModifiedTime], [LastModifiedTimeUtc],@HistoryAction  	FROM deletedEND